#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Transaction {
    pub from: String,
    pub to: String,
    pub amount: u64,
    pub nonce: u64,
}

pub fn validate_transaction(tx: &Transaction) -> Result<(), String> {
    if tx.from.trim().is_empty() {
        return Err("from address is required".to_string());
    }
    if tx.to.trim().is_empty() {
        return Err("to address is required".to_string());
    }
    if tx.amount == 0 {
        return Err("amount must be greater than zero".to_string());
    }
    Ok(())
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct TransferRequest {
    pub from: String,
    pub to: String,
    pub amount: u64,
    pub fee: u64,
    pub nonce: u64,
}

pub fn validate_transfer_request(request: &TransferRequest) -> Result<(), String> {
    if request.from.trim().is_empty() {
        return Err("from address is required".to_string());
    }
    if request.to.trim().is_empty() {
        return Err("to address is required".to_string());
    }
    if request.amount == 0 {
        return Err("amount must be greater than zero".to_string());
    }
    request
        .amount
        .checked_add(request.fee)
        .ok_or_else(|| "amount plus fee overflowed".to_string())?;
    Ok(())
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct SignedTransfer {
    pub signer: String,
    pub recipient: String,
    pub amount: u64,
    pub nonce: u64,
    pub signature: Vec<u8>,
}

pub fn validate_signed_transfer(tx: &SignedTransfer) -> Result<(), String> {
    if tx.signer.trim().is_empty() {
        return Err("signer is required".to_string());
    }
    if tx.recipient.trim().is_empty() {
        return Err("recipient is required".to_string());
    }
    if tx.amount == 0 {
        return Err("amount must be greater than zero".to_string());
    }
    if tx.signature.is_empty() {
        return Err("signature is required".to_string());
    }
    Ok(())
}
